function strassen(A, B):
    if base_case:
        return standard_mult(A, B)

    A11, A12, A21, A22 = split(A)
    B11, B12, B21, B22 = split(B)

    M1 = strassen(A11 + A22, B11 + B22)
    M2 = strassen(A21 + A22, B11)
    ... # Compute M3-M7

    C11 = M1 + M4 - M5 + M7
    ... # Combine other quadrants
    return combine(C11, C12, C21, C22)
